static bool dupAfter(int rem,int fid,int a,int b,int c,int e0,int e1){if(a==b||a==c||b==c)return true;auto k=tkey(a,b,c);int base=a;if(inc[b].size()<inc[base].size())base=b;if(inc[c].size()<inc[base].size())base=c;cleanInc(base);for(int id:inc[base])if(aliveF[id]&&id!=fid&&id!=e0&&id!=e1){if(hasv(F[id],rem))continue;if(tkey(F[id].a,F[id].b,F[id].c)==k)return true;}return false;}
struct Eval{bool ok=false;double cost=1e100,newErr=0;};
static Eval evalCollapse(int keep,int rem,const int ef[2],double emax,double ndotMin,double planeMax,double areaRelMin){Eval r;double d=normv(P[keep]-P[rem]);r.newErr=max(errV[keep],errV[rem]+d);if(r.newErr>emax)return r;cleanInc(rem);double wp=0,wf=0,al=0;int touched=0;for(int id:inc[rem])if(aliveF[id]&&id!=ef[0]&&id!=ef[1]){Face old=F[id];int a=old.a,b=old.b,c=old.c;if(a==rem)a=keep;if(b==rem)b=keep;if(c==rem)c=keep;if(dupAfter(rem,id,a,b,c,ef[0],ef[1]))return r;Vec3 no=crossv(P[old.b]-P[old.a],P[old.c]-P[old.a]);Vec3 nn=crossv(P[b]-P[a],P[c]-P[a]);double lo=normv(no),ln=normv(nn);if(!(lo>1e-30)||!(ln>1e-30)||ln<lo*areaRelMin)return r;double co=dotv(no,nn)/(lo*ln);if(co<ndotMin)return r;double pd=fabs(dotv(no*(1.0/lo),P[keep]-P[old.a]));if(pd>planeMax)return r;wp=max(wp,pd);wf=max(wf,1.0-co);al=max(al,max(0.0,1.0-ln/lo));touched++;}if(!touched)return r;r.ok=true;r.cost=0.70*d/(EPS+1e-30)+1.55*r.newErr/(EPS+1e-30)+2.20*wp/(EPS+1e-30)+175.0*wf+0.06*touched+0.04*al;return r;}
static bool applyCollapse(int keep,int rem,const int ef[2],double ne){for(int i=0;i<2;i++)if(aliveF[ef[i]]){aliveF[ef[i]]=0;aliveFaces--;}cleanInc(rem);vector<int>mv=inc[rem];for(int id:mv)if(aliveF[id]&&hasv(F[id],rem)){Face&f=F[id];if(f.a==rem)f.a=keep;if(f.b==rem)f.b=keep;if(f.c==rem)f.c=keep;inc[keep].push_back(id);}aliveV[rem]=0;errV[keep]=ne;inc[rem].clear();if(inc[keep].size()>512)cleanInc(keep);return true;}
struct Cand{double c;int u,v;};struct Cmp{bool operator()(const Cand&a,const Cand&b)const{return a.c>b.c;}};
static void simplifyPass(double efraction,double ndotMin,double planeFrac,double areaRelMin,double limit){double emax=EPS*efraction,planeMax=EPS*planeFrac;priority_queue<Cand,vector<Cand>,Cmp>pq;unordered_set<long long>seen;seen.reserve((size_t)M*3+8);for(int i=0;i<M;i++)if(aliveF[i]){int a[3]={F[i].a,F[i].b,F[i].c};for(int e=0;e<3;e++){int u=a[e],v=a[(e+1)%3];long long k=ekey(u,v);if(seen.insert(k).second)pq.push({normv(P[u]-P[v]),u,v});}}while(!pq.empty()&&elapsed()<limit){Cand c=pq.top();pq.pop();int u=c.u,v=c.v;if(u<0||v<0||u>=N||v>=N||!aliveV[u]||!aliveV[v])continue;int ef[2],op[2];if(!edgeFaces(u,v,ef,op)||!linkOK(u,v,op[0],op[1]))continue;Eval eu=evalCollapse(u,v,ef,emax,ndotMin,planeMax,areaRelMin),ev=evalCollapse(v,u,ef,emax,ndotMin,planeMax,areaRelMin);if(!eu.ok&&!ev.ok)continue;int keep=u,rem=v;Eval best=eu;if(ev.ok&&(!eu.ok||ev.cost<eu.cost)){keep=v;rem=u;best=ev;}applyCollapse(keep,rem,ef,best.newErr);cleanInc(keep);unordered_set<long long>loc;loc.reserve(256);for(int id:inc[keep])if(aliveF[id]){int a[3]={F[id].a,F[id].b,F[id].c};for(int e=0;e<3;e++){int x=a[e],y=a[(e+1)%3];if(aliveV[x]&&aliveV[y]&&x!=y&&loc.insert(ekey(x,y)).second)pq.push({0.86*normv(P[x]-P[y]),x,y});}}}}
static bool verifyClosed(){unordered_map<long long,int>cnt;cnt.reserve((size_t)aliveFaces*3+8);for(int i=0;i<M;i++)if(aliveF[i]){Face f=F[i];if(f.a==f.b||f.a==f.c||f.b==f.c)return false;if(!aliveV[f.a]||!aliveV[f.b]||!aliveV[f.c])return false;if(normv(crossv(P[f.b]-P[f.a],P[f.c]-P[f.a]))<=1e-30)return false;cnt[ekey(f.a,f.b)]++;cnt[ekey(f.b,f.c)]++;cnt[ekey(f.c,f.a)]++;}for(auto&kv:cnt)if(kv.second!=2)return false;return true;}
static void outputMesh(){if(!verifyClosed()){outputOriginal();return;}vector<int>id(N,-1);int nv=0,nf=0;for(int i=0;i<N;i++)if(aliveV[i])id[i]=++nv;for(int i=0;i<M;i++)if(aliveF[i])nf++;cout.setf(ios::fixed);cout<<setprecision(10);cout<<nv<<" "<<nf<<"\n";for(int i=0;i<N;i++)if(aliveV[i])cout<<"v "<<P[i].x<<" "<<P[i].y<<" "<<P[i].z<<"\n";for(int i=0;i<M;i++)if(aliveF[i])cout<<"f "<<id[F[i].a]<<" "<<id[F[i].b]<<" "<<id[F[i].c]<<"\n";}
